#!/usr/bin/env node
// @author kongweiguang

import { mkdirSync, writeFileSync } from "node:fs";
import path from "node:path";
import { performance } from "node:perf_hooks";
import { fileURLToPath } from "node:url";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const args = parseArgs(process.argv.slice(2));
const outputPath = path.resolve(
  repoRoot,
  args.output ?? ".updeng/docs/verification/terminal-input-baseline.json",
);

const scenarios = [
  {
    data: "a",
    iterations: readPositiveInteger(args["single-key-iterations"], 20_000, "--single-key-iterations"),
    name: "single-key",
  },
  {
    data: "\n",
    iterations: readPositiveInteger(args["agent-enter-iterations"], 20_000, "--agent-enter-iterations"),
    name: "agent-shift-enter-lf",
  },
  {
    data: "中文输入法组合-かな-한글-🙂",
    iterations: readPositiveInteger(args["ime-iterations"], 10_000, "--ime-iterations"),
    name: "ime-unicode-composition",
  },
  {
    data: buildPastePayload(1024),
    iterations: readPositiveInteger(args["paste-1k-iterations"], 3_000, "--paste-1k-iterations"),
    name: "paste-1k",
  },
  {
    data: buildPastePayload(64 * 1024),
    iterations: readPositiveInteger(args["paste-64k-iterations"], 300, "--paste-64k-iterations"),
    name: "paste-64k",
  },
  {
    data: buildPastePayload(1024 * 1024),
    iterations: readPositiveInteger(args["paste-1m-iterations"], 30, "--paste-1m-iterations"),
    name: "paste-1m",
  },
];

const report = {
  schemaVersion: 1,
  generatedAt: new Date().toISOString(),
  environment: {
    node: process.version,
    platform: process.platform,
  },
  note:
    "Measures the current terminal_write JSON payload cost in Node as a repeatable proxy. Full WebView/Tauri invoke latency still requires runtime smoke; this report decides whether raw IPC needs deeper investigation.",
  results: scenarios.map(runScenario),
};
report.summary = summarizeReport(report.results);

mkdirSync(path.dirname(outputPath), { recursive: true });
writeFileSync(outputPath, `${JSON.stringify(report, null, 2)}\n`, "utf8");

console.log(
  `Terminal input baseline: ${report.results.length} scenarios, worst stringify p95 ${report.summary.stringifyP95MaxMs.toFixed(
    4,
  )} ms, worst parse p95 ${report.summary.parseP95MaxMs.toFixed(4)} ms.`,
);
console.log(`Report: ${path.relative(repoRoot, outputPath).replaceAll("\\", "/")}`);

if (!report.summary.pass) {
  process.exitCode = 1;
}

function runScenario(scenario) {
  const payload = {
    data: scenario.data,
    sessionId: "terminal-input-baseline",
  };
  const utf8Bytes = Buffer.byteLength(scenario.data, "utf8");
  const stringifySamples = [];
  const parseSamples = [];
  let json = "";

  for (let index = 0; index < scenario.iterations; index += 1) {
    let startedAt = performance.now();
    json = JSON.stringify(payload);
    stringifySamples.push(performance.now() - startedAt);

    startedAt = performance.now();
    JSON.parse(json);
    parseSamples.push(performance.now() - startedAt);
  }

  const jsonBytes = Buffer.byteLength(json, "utf8");
  const stringifyMs = percentileSummary(stringifySamples);
  const parseMs = percentileSummary(parseSamples);
  const pass = stringifyMs.p95 <= thresholdForBytes(utf8Bytes) && parseMs.p95 <= thresholdForBytes(utf8Bytes);

  return {
    name: scenario.name,
    input: {
      chars: scenario.data.length,
      iterations: scenario.iterations,
      utf8Bytes,
    },
    json: {
      bytes: jsonBytes,
      expansionRatio: Number((jsonBytes / Math.max(utf8Bytes, 1)).toFixed(4)),
    },
    pass,
    thresholds: {
      p95Ms: thresholdForBytes(utf8Bytes),
    },
    timing: {
      parseMs,
      stringifyMs,
    },
  };
}

function summarizeReport(results) {
  const stringifyP95MaxMs = Math.max(...results.map((result) => result.timing.stringifyMs.p95));
  const parseP95MaxMs = Math.max(...results.map((result) => result.timing.parseMs.p95));
  const worstScenario =
    results.toSorted((left, right) => right.timing.stringifyMs.p95 - left.timing.stringifyMs.p95)[0]?.name ?? null;
  return {
    parseP95MaxMs,
    pass: results.every((result) => result.pass),
    stringifyP95MaxMs,
    worstScenario,
  };
}

function buildPastePayload(bytes) {
  const line = "kerminal-input-paste-baseline ";
  let output = "";
  while (Buffer.byteLength(output, "utf8") < bytes) {
    output += `${line}${String(output.length).padStart(8, "0")}\r\n`;
  }
  return output.slice(0, bytes);
}

function thresholdForBytes(bytes) {
  if (bytes <= 1024) {
    return 1;
  }
  if (bytes <= 64 * 1024) {
    return 8;
  }
  return 75;
}

function percentileSummary(values) {
  if (values.length === 0) {
    return { max: 0, p50: 0, p95: 0, p99: 0 };
  }
  const sorted = [...values].sort((left, right) => left - right);
  return {
    max: sorted.at(-1),
    p50: percentile(sorted, 0.5),
    p95: percentile(sorted, 0.95),
    p99: percentile(sorted, 0.99),
  };
}

function percentile(sorted, ratio) {
  return sorted[Math.min(sorted.length - 1, Math.floor((sorted.length - 1) * ratio))];
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let index = 0; index < rawArgs.length; index += 1) {
    const arg = rawArgs[index];
    if (!arg.startsWith("--")) {
      continue;
    }
    const key = arg.slice(2);
    const value = rawArgs[index + 1];
    if (!value || value.startsWith("--")) {
      parsed[key] = true;
      continue;
    }
    parsed[key] = value;
    index += 1;
  }
  return parsed;
}

function readPositiveInteger(value, fallback, label) {
  const parsed = value === undefined ? fallback : Number.parseInt(value, 10);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    throw new Error(`${label} must be a positive integer.`);
  }
  return parsed;
}

//! 本地 PTY 进程与 ConPTY 生命周期守护。
//!
//! @author kongweiguang

use portable_pty::{Child, ChildKiller, ExitStatus, MasterPty, PtySize};
use std::{
    fmt,
    io::{self, Read, Write},
    sync::{
        atomic::{AtomicBool, Ordering},
        Arc, Mutex,
    },
};

pub type PtyChildHandle = Box<dyn Child + Send + Sync>;
pub type SharedPtyChildHandle = Arc<Mutex<PtyChildHandle>>;

type PtyChildKiller = Box<dyn ChildKiller + Send + Sync>;
type SharedPtyChildKiller = Arc<Mutex<PtyChildKiller>>;
type PtyMasterHandle = Box<dyn MasterPty + Send>;

/// 在 Windows 上串行化 ConPTY 创建/销毁；其它平台直接执行。
pub fn with_conpty_lifecycle_lock<T>(operation: impl FnOnce() -> T) -> T {
    platform::with_conpty_lifecycle_lock(operation)
}

pub struct PtyProcessGuard {
    child: SharedPtyChildHandle,
    killer: SharedPtyChildKiller,
    kill_requested: AtomicBool,
    pid: Option<u32>,
    #[cfg(windows)]
    _job: Option<platform::WindowsJobObject>,
}

impl PtyProcessGuard {
    pub fn new(child: PtyChildHandle) -> Self {
        let pid = child.process_id();
        let killer = Arc::new(Mutex::new(child.clone_killer()));

        #[cfg(windows)]
        let job = match platform::WindowsJobObject::attach_to_child(&child) {
            Ok(job) => job,
            Err(error) => {
                tauri_plugin_log::log::warn!(
                    "failed to attach PTY process to Windows Job Object: {error}"
                );
                None
            }
        };

        Self {
            child: Arc::new(Mutex::new(child)),
            killer,
            kill_requested: AtomicBool::new(false),
            pid,
            #[cfg(windows)]
            _job: job,
        }
    }

    pub fn pid(&self) -> Option<u32> {
        self.pid
    }

    pub fn shared_child(&self) -> SharedPtyChildHandle {
        self.child.clone()
    }

    pub fn try_wait_status(&self) -> io::Result<Option<ExitStatus>> {
        let mut child = self
            .child
            .lock()
            .map_err(|_| io::Error::other("PTY child lock poisoned"))?;
        child.try_wait()
    }

    /// Requests process termination at most once.
    ///
    /// The guard first tries to observe an already-exited child to avoid
    /// signalling a stale PID on Unix cloned killers. If the child lock is busy,
    /// it falls back to the cloned killer so close/drop never blocks on waiter
    /// threads.
    pub fn best_effort_kill(&self) -> bool {
        if self.kill_requested.swap(true, Ordering::SeqCst) {
            return false;
        }

        if let Ok(mut child) = self.child.try_lock() {
            if matches!(child.try_wait(), Ok(Some(_))) {
                return false;
            }
        }

        let Ok(mut killer) = self.killer.lock() else {
            return false;
        };
        let _ = killer.kill();
        true
    }

    #[cfg(windows)]
    pub fn has_windows_job(&self) -> bool {
        self._job.is_some()
    }
}

impl fmt::Debug for PtyProcessGuard {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter
            .debug_struct("PtyProcessGuard")
            .field("pid", &self.pid)
            .field(
                "kill_requested",
                &self.kill_requested.load(Ordering::SeqCst),
            )
            .finish_non_exhaustive()
    }
}

impl Drop for PtyProcessGuard {
    fn drop(&mut self) {
        let _ = self.best_effort_kill();
    }
}

pub struct PtyMasterGuard {
    inner: Option<PtyMasterHandle>,
}

impl PtyMasterGuard {
    pub fn new(master: PtyMasterHandle) -> Self {
        Self {
            inner: Some(master),
        }
    }

    pub fn resize(&self, size: PtySize) -> Result<(), String> {
        self.inner().resize(size).map_err(|error| error.to_string())
    }

    pub fn try_clone_reader(&self) -> Result<Box<dyn Read + Send>, String> {
        self.inner()
            .try_clone_reader()
            .map_err(|error| error.to_string())
    }

    pub fn take_writer(&self) -> Result<Box<dyn Write + Send>, String> {
        self.inner()
            .take_writer()
            .map_err(|error| error.to_string())
    }

    fn inner(&self) -> &PtyMasterHandle {
        self.inner
            .as_ref()
            .expect("PTY master handle must exist before drop")
    }
}

impl fmt::Debug for PtyMasterGuard {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter
            .debug_struct("PtyMasterGuard")
            .finish_non_exhaustive()
    }
}

impl Drop for PtyMasterGuard {
    fn drop(&mut self) {
        if let Some(master) = self.inner.take() {
            with_conpty_lifecycle_lock(|| drop(master));
        }
    }
}

#[cfg(windows)]
mod platform {
    use super::PtyChildHandle;
    use std::{ffi::c_void, io, mem::size_of, os::windows::io::RawHandle, ptr, sync::Mutex};
    use windows_sys::Win32::{
        Foundation::{CloseHandle, HANDLE, INVALID_HANDLE_VALUE},
        System::JobObjects::{
            AssignProcessToJobObject, CreateJobObjectW, JobObjectExtendedLimitInformation,
            SetInformationJobObject, JOBOBJECT_EXTENDED_LIMIT_INFORMATION,
            JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE,
        },
    };

    static CONPTY_LIFECYCLE_LOCK: Mutex<()> = Mutex::new(());

    pub(super) fn with_conpty_lifecycle_lock<T>(operation: impl FnOnce() -> T) -> T {
        let _guard = CONPTY_LIFECYCLE_LOCK
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        operation()
    }

    #[derive(Debug)]
    pub(super) struct WindowsJobObject {
        handle: HANDLE,
    }

    unsafe impl Send for WindowsJobObject {}

    impl WindowsJobObject {
        pub(super) fn attach_to_child(child: &PtyChildHandle) -> io::Result<Option<Self>> {
            let Some(process_handle) = child.as_raw_handle() else {
                return Ok(None);
            };
            Self::attach_to_process_handle(process_handle).map(Some)
        }

        fn attach_to_process_handle(process_handle: RawHandle) -> io::Result<Self> {
            let handle = unsafe { CreateJobObjectW(ptr::null(), ptr::null()) };
            if handle.is_null() || handle == INVALID_HANDLE_VALUE {
                return Err(io::Error::last_os_error());
            }

            let job = Self { handle };
            let mut info = JOBOBJECT_EXTENDED_LIMIT_INFORMATION::default();
            info.BasicLimitInformation.LimitFlags = JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE;

            let configured = unsafe {
                SetInformationJobObject(
                    job.handle,
                    JobObjectExtendedLimitInformation,
                    &info as *const _ as *const c_void,
                    size_of::<JOBOBJECT_EXTENDED_LIMIT_INFORMATION>() as u32,
                )
            };
            if configured == 0 {
                return Err(io::Error::last_os_error());
            }

            let assigned =
                unsafe { AssignProcessToJobObject(job.handle, process_handle as HANDLE) };
            if assigned == 0 {
                return Err(io::Error::last_os_error());
            }

            Ok(job)
        }
    }

    impl Drop for WindowsJobObject {
        fn drop(&mut self) {
            if !self.handle.is_null() && self.handle != INVALID_HANDLE_VALUE {
                unsafe {
                    CloseHandle(self.handle);
                }
            }
        }
    }
}

#[cfg(not(windows))]
mod platform {
    pub(super) fn with_conpty_lifecycle_lock<T>(operation: impl FnOnce() -> T) -> T {
        operation()
    }
}

//! Agent terminal OSC signal detector.
//!
//! @author kongweiguang

pub use crate::models::terminal::{TerminalAgentKind, TerminalAgentSignal, TerminalAgentStatus};

const OSC_PREFIX: &str = "\u{1b}]";
const OSC_ST_TERMINATOR: &str = "\u{1b}\\";
const DEFAULT_MAX_OSC_SEQUENCE_BYTES: usize = 8 * 1024;
const KERMINAL_AGENT_NOTIFY_PREFIX: &str = "777;notify;Kerminal;";

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TerminalAgentSignalObservation {
    pub data: String,
    pub signals: Vec<TerminalAgentSignal>,
}

#[derive(Debug, Clone)]
pub struct TerminalAgentSignalDetector {
    armed_agent: Option<TerminalAgentKind>,
    osc_buffer: String,
    max_osc_sequence_bytes: usize,
}

impl Default for TerminalAgentSignalDetector {
    fn default() -> Self {
        Self::new()
    }
}

impl TerminalAgentSignalDetector {
    pub fn new() -> Self {
        Self::with_max_osc_sequence_bytes(DEFAULT_MAX_OSC_SEQUENCE_BYTES)
    }

    pub fn with_max_osc_sequence_bytes(max_osc_sequence_bytes: usize) -> Self {
        Self {
            armed_agent: None,
            osc_buffer: String::new(),
            max_osc_sequence_bytes: max_osc_sequence_bytes.max(OSC_PREFIX.len() + 1),
        }
    }

    pub fn armed_agent(&self) -> Option<TerminalAgentKind> {
        self.armed_agent
    }

    pub fn observe(&mut self, data: &str) -> Vec<TerminalAgentSignal> {
        self.observe_inner(data, false).signals
    }

    pub fn observe_and_filter(&mut self, data: &str) -> TerminalAgentSignalObservation {
        self.observe_inner(data, true)
    }

    fn observe_inner(
        &mut self,
        data: &str,
        filter_kerminal_marker: bool,
    ) -> TerminalAgentSignalObservation {
        if data.is_empty() && self.osc_buffer.is_empty() {
            return TerminalAgentSignalObservation {
                data: String::new(),
                signals: Vec::new(),
            };
        }

        let mut source = String::new();
        if !self.osc_buffer.is_empty() {
            source.push_str(&self.osc_buffer);
            self.osc_buffer.clear();
        }
        source.push_str(data);

        let mut signals = Vec::new();
        let mut filtered_data = String::with_capacity(data.len());
        let mut cursor = 0;

        while cursor < source.len() {
            let Some(relative_start) = source[cursor..].find(OSC_PREFIX) else {
                if let Some(partial_start) = partial_osc_prefix_start(&source, cursor) {
                    if filter_kerminal_marker {
                        filtered_data.push_str(&source[cursor..partial_start]);
                    }
                    self.osc_buffer.push_str(&source[partial_start..]);
                } else if filter_kerminal_marker {
                    filtered_data.push_str(&source[cursor..]);
                }
                break;
            };
            let start = cursor + relative_start;
            let payload_start = start + OSC_PREFIX.len();
            if filter_kerminal_marker {
                filtered_data.push_str(&source[cursor..start]);
            }

            let Some(terminator) = find_osc_terminator(&source, payload_start) else {
                if source.len().saturating_sub(start) <= self.max_osc_sequence_bytes {
                    self.osc_buffer.push_str(&source[start..]);
                } else if filter_kerminal_marker {
                    filtered_data.push_str(&source[start..]);
                }
                break;
            };

            let sequence_len = terminator.index + terminator.len - start;
            let payload = &source[payload_start..terminator.index];
            if sequence_len <= self.max_osc_sequence_bytes {
                self.observe_osc_payload(payload, &mut signals);
            }
            if filter_kerminal_marker && !is_kerminal_agent_marker(payload) {
                filtered_data.push_str(&source[start..terminator.index + terminator.len]);
            }
            cursor = terminator.index + terminator.len;
        }

        TerminalAgentSignalObservation {
            data: filtered_data,
            signals,
        }
    }

    pub fn finish_pty(&mut self) -> Option<TerminalAgentSignal> {
        let agent = self.armed_agent.take()?;
        self.osc_buffer.clear();
        Some(TerminalAgentSignal {
            agent,
            status: TerminalAgentStatus::Exited,
        })
    }

    fn observe_osc_payload(&mut self, payload: &str, signals: &mut Vec<TerminalAgentSignal>) {
        if let Some(signal) = self.parse_kerminal_agent_signal(payload) {
            self.armed_agent = Some(signal.agent);
            signals.push(signal);
            return;
        }

        if let Some(agent) = parse_osc133_command_agent(payload) {
            self.armed_agent = Some(agent);
            signals.push(TerminalAgentSignal {
                agent,
                status: TerminalAgentStatus::Working,
            });
            return;
        }

        if is_osc9_attention(payload) {
            if let Some(agent) = self.armed_agent {
                signals.push(TerminalAgentSignal {
                    agent,
                    status: TerminalAgentStatus::Attention,
                });
            }
        }
    }

    fn parse_kerminal_agent_signal(&self, payload: &str) -> Option<TerminalAgentSignal> {
        let rest = payload.strip_prefix(KERMINAL_AGENT_NOTIFY_PREFIX)?;
        let mut parts = rest.split(';');
        let agent = TerminalAgentKind::from_id(parts.next()?)?;
        let status = TerminalAgentStatus::from_marker_event(parts.next()?)?;
        Some(TerminalAgentSignal { agent, status })
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct OscTerminator {
    index: usize,
    len: usize,
}

fn find_osc_terminator(source: &str, payload_start: usize) -> Option<OscTerminator> {
    let tail = &source[payload_start..];
    let bel = tail.find('\u{7}').map(|index| OscTerminator {
        index: payload_start + index,
        len: '\u{7}'.len_utf8(),
    });
    let st = tail.find(OSC_ST_TERMINATOR).map(|index| OscTerminator {
        index: payload_start + index,
        len: OSC_ST_TERMINATOR.len(),
    });

    match (bel, st) {
        (Some(left), Some(right)) => Some(if left.index <= right.index {
            left
        } else {
            right
        }),
        (Some(terminator), None) | (None, Some(terminator)) => Some(terminator),
        (None, None) => None,
    }
}

fn partial_osc_prefix_start(source: &str, cursor: usize) -> Option<usize> {
    let tail = &source[cursor..];
    (1..OSC_PREFIX.len())
        .rev()
        .find(|length| tail.ends_with(&OSC_PREFIX[..*length]))
        .map(|length| source.len() - length)
}

fn parse_osc133_command_agent(payload: &str) -> Option<TerminalAgentKind> {
    let rest = payload.strip_prefix("133;")?;
    let mut parts = rest.splitn(2, ';');
    let marker = parts.next()?.trim();
    if !marker.eq_ignore_ascii_case("C") {
        return None;
    }
    detect_agent_command(parts.next().unwrap_or_default())
}

fn is_osc9_attention(payload: &str) -> bool {
    payload == "9" || payload.starts_with("9;")
}

fn is_kerminal_agent_marker(payload: &str) -> bool {
    payload.starts_with(KERMINAL_AGENT_NOTIFY_PREFIX)
}

fn detect_agent_command(command: &str) -> Option<TerminalAgentKind> {
    let mut cursor = 0;
    let mut allow_env_assignments = true;

    while let Some(token) = next_shell_token(command, &mut cursor) {
        let normalized = normalize_command_token(&token);
        if normalized.is_empty() {
            continue;
        }

        if allow_env_assignments && looks_like_env_assignment(&normalized) {
            continue;
        }

        allow_env_assignments = false;
        if matches!(normalized.as_str(), "command" | "exec" | "sudo") {
            continue;
        }
        if normalized == "env" {
            allow_env_assignments = true;
            continue;
        }

        return TerminalAgentKind::from_id(&normalized);
    }

    None
}

fn next_shell_token(command: &str, cursor: &mut usize) -> Option<String> {
    let bytes = command.as_bytes();
    while *cursor < bytes.len() && bytes[*cursor].is_ascii_whitespace() {
        *cursor += 1;
    }
    if *cursor >= bytes.len() {
        return None;
    }

    let quote = match bytes[*cursor] {
        b'\'' => Some('\''),
        b'"' => Some('"'),
        _ => None,
    };
    if let Some(quote) = quote {
        *cursor += quote.len_utf8();
        let start = *cursor;
        while *cursor < command.len() {
            let Some(character) = command[*cursor..].chars().next() else {
                break;
            };
            if character == quote {
                let token = command[start..*cursor].to_owned();
                *cursor += character.len_utf8();
                return Some(token);
            }
            *cursor += character.len_utf8();
        }
        return Some(command[start..].to_owned());
    }

    let start = *cursor;
    while *cursor < command.len() {
        let Some(character) = command[*cursor..].chars().next() else {
            break;
        };
        if character.is_whitespace() {
            break;
        }
        *cursor += character.len_utf8();
    }
    Some(command[start..*cursor].to_owned())
}

fn normalize_command_token(token: &str) -> String {
    let token = token.trim_matches(|character| {
        matches!(
            character,
            '"' | '\'' | '`' | ';' | ',' | '(' | ')' | '[' | ']'
        )
    });
    let token = token.replace('\\', "/");
    let executable = token.rsplit('/').next().unwrap_or(token.as_str());
    let mut normalized = executable.to_ascii_lowercase();
    for suffix in [".exe", ".cmd", ".bat", ".ps1"] {
        if normalized.ends_with(suffix) {
            normalized.truncate(normalized.len() - suffix.len());
            break;
        }
    }
    normalized
}

fn looks_like_env_assignment(token: &str) -> bool {
    let Some((name, value)) = token.split_once('=') else {
        return false;
    };
    !name.is_empty()
        && !value.is_empty()
        && name
            .chars()
            .all(|character| character == '_' || character.is_ascii_alphanumeric())
}

//! PTY 输出侧的最小终端查询响应器。
//!
//! @author kongweiguang

const ESC: char = '\u{1b}';
const BEL: u8 = 0x07;
const CSI_INTRO: u8 = b'[';
const OSC_INTRO: u8 = b']';
const ST_FINAL: u8 = b'\\';
const MAX_PENDING_ESCAPE_BYTES: usize = 256;

/// Primary DA response: VT100 with advanced video option.
pub const PRIMARY_DA_RESPONSE: &str = "\u{1b}[?1;2c";
/// Secondary DA response: minimal xterm-compatible terminal id/version tuple.
pub const SECONDARY_DA_RESPONSE: &str = "\u{1b}[>0;0;0c";
/// Cursor position response used before the renderer can answer CPR itself.
pub const STARTUP_CPR_RESPONSE: &str = "\u{1b}[1;1R";

/// 单次 PTY 输出观察后的过滤结果和需要回写给 PTY child 的响应。
#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct TerminalEscapeObservation {
    pub data: String,
    pub responses: Vec<&'static str>,
}

/// 仅处理启动期 terminal query 的小状态机。
#[derive(Debug, Default)]
pub struct TerminalEscapeResponder {
    pending_escape: String,
    seen_visible_output: bool,
}

impl TerminalEscapeResponder {
    pub fn new() -> Self {
        Self::default()
    }

    /// 观察 PTY 输出，过滤由后端代答的 DA/DSR query，并返回应写回 PTY 的响应。
    pub fn observe(&mut self, data: &str) -> TerminalEscapeObservation {
        let mut input = String::new();
        if !self.pending_escape.is_empty() {
            input.push_str(&self.pending_escape);
            self.pending_escape.clear();
        }
        input.push_str(data);

        let mut output = String::with_capacity(input.len());
        let mut responses = Vec::new();
        let mut index = 0;

        while index < input.len() {
            let Some(escape_offset) = input[index..].find(ESC) else {
                self.push_visible(&mut output, &input[index..]);
                break;
            };
            let escape_start = index + escape_offset;
            if escape_start > index {
                self.push_visible(&mut output, &input[index..escape_start]);
            }

            let bytes = input.as_bytes();
            if escape_start + 1 >= input.len() {
                self.hold_or_flush_pending(&mut output, &input[escape_start..]);
                break;
            }

            match bytes[escape_start + 1] {
                CSI_INTRO => match csi_end(&input, escape_start) {
                    Some(sequence_end) => {
                        let sequence = &input[escape_start..sequence_end];
                        match classify_csi(sequence) {
                            CsiQuery::PrimaryDa => {
                                responses.push(PRIMARY_DA_RESPONSE);
                            }
                            CsiQuery::SecondaryDa => {
                                responses.push(SECONDARY_DA_RESPONSE);
                            }
                            CsiQuery::StartupCpr if !self.seen_visible_output => {
                                responses.push(STARTUP_CPR_RESPONSE);
                            }
                            CsiQuery::StartupCpr | CsiQuery::Other => {
                                output.push_str(sequence);
                            }
                        }
                        index = sequence_end;
                    }
                    None => {
                        self.hold_or_flush_pending(&mut output, &input[escape_start..]);
                        break;
                    }
                },
                OSC_INTRO => match osc_end(&input, escape_start) {
                    Some(sequence_end) => {
                        output.push_str(&input[escape_start..sequence_end]);
                        index = sequence_end;
                    }
                    None => {
                        self.hold_or_flush_pending(&mut output, &input[escape_start..]);
                        break;
                    }
                },
                _ => {
                    let sequence_end = (escape_start + 2).min(input.len());
                    output.push_str(&input[escape_start..sequence_end]);
                    index = sequence_end;
                }
            }
        }

        TerminalEscapeObservation {
            data: output,
            responses,
        }
    }

    pub fn pending_len(&self) -> usize {
        self.pending_escape.len()
    }

    fn push_visible(&mut self, output: &mut String, value: &str) {
        if value.chars().any(|ch| !ch.is_control()) {
            self.seen_visible_output = true;
        }
        output.push_str(value);
    }

    fn hold_or_flush_pending(&mut self, output: &mut String, value: &str) {
        if value.len() > MAX_PENDING_ESCAPE_BYTES {
            output.push_str(value);
            self.pending_escape.clear();
            return;
        }
        self.pending_escape.push_str(value);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CsiQuery {
    PrimaryDa,
    SecondaryDa,
    StartupCpr,
    Other,
}

fn classify_csi(sequence: &str) -> CsiQuery {
    let bytes = sequence.as_bytes();
    if bytes.len() < 3 || bytes[0] != ESC as u8 || bytes[1] != CSI_INTRO {
        return CsiQuery::Other;
    }

    let final_byte = *bytes.last().unwrap_or(&0);
    let params = &sequence[2..sequence.len() - 1];
    match final_byte {
        b'c' if params.is_empty() || params == "0" => CsiQuery::PrimaryDa,
        b'c' if params == ">" || params == ">0" => CsiQuery::SecondaryDa,
        b'n' if params == "6" => CsiQuery::StartupCpr,
        _ => CsiQuery::Other,
    }
}

fn csi_end(input: &str, escape_start: usize) -> Option<usize> {
    let bytes = input.as_bytes();
    let mut index = escape_start + 2;
    while index < bytes.len() {
        if (0x40..=0x7e).contains(&bytes[index]) {
            return Some(index + 1);
        }
        index += 1;
    }
    None
}

fn osc_end(input: &str, escape_start: usize) -> Option<usize> {
    let bytes = input.as_bytes();
    let mut index = escape_start + 2;
    while index < bytes.len() {
        if bytes[index] == BEL {
            return Some(index + 1);
        }
        if bytes[index] == ESC as u8 && index + 1 < bytes.len() && bytes[index + 1] == ST_FINAL {
            return Some(index + 2);
        }
        index += 1;
    }
    None
}

//! Local PTY output coalescing and terminal event ordering.
//!
//! @author kongweiguang

use crate::models::terminal::TerminalOutputEvent;

const DEFAULT_FLUSH_BYTES: usize = 64 * 1024;
const DEFAULT_MAX_PENDING_BYTES: usize = 4 * 1024 * 1024;
const DEFAULT_OVERFLOW_NOTICE: &str =
    "\r\n\x1b[0m\x1b[33m[Kerminal] terminal output backlog exceeded; stale output was dropped.\x1b[0m\r\n";

/// Receives already prepared terminal output events from the pump.
pub trait PtyOutputSink {
    /// Returns false when the downstream consumer is no longer available.
    fn on_terminal_output(&mut self, event: TerminalOutputEvent) -> bool;
}

impl<F> PtyOutputSink for F
where
    F: FnMut(TerminalOutputEvent) -> bool,
{
    fn on_terminal_output(&mut self, event: TerminalOutputEvent) -> bool {
        self(event)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PtyOutputPumpConfig {
    /// Flush once pending output reaches this size. Time based idle flushing is
    /// owned by the reader/flusher adapter so the pump remains deterministic.
    pub flush_bytes: usize,
    /// Maximum bytes the pump may hold before dropping stale pending output.
    pub max_pending_bytes: usize,
    /// Notice inserted when stale pending output has to be dropped.
    pub overflow_notice: String,
}

impl Default for PtyOutputPumpConfig {
    fn default() -> Self {
        Self {
            flush_bytes: DEFAULT_FLUSH_BYTES,
            max_pending_bytes: DEFAULT_MAX_PENDING_BYTES,
            overflow_notice: DEFAULT_OVERFLOW_NOTICE.to_owned(),
        }
    }
}

impl PtyOutputPumpConfig {
    fn normalized(mut self) -> Self {
        self.flush_bytes = self.flush_bytes.max(1);
        self.max_pending_bytes = self
            .max_pending_bytes
            .max(1)
            .max(self.overflow_notice.len());
        self
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct PtyOutputPumpStats {
    pub input_chunks: u64,
    pub input_bytes: u64,
    pub data_events: u64,
    pub closed_events: u64,
    pub error_events: u64,
    pub output_bytes: u64,
    pub max_pending_bytes: usize,
    pub dropped_bytes: u64,
    pub overflow_count: u64,
}

/// Stateful output pump for a single PTY session.
pub struct PtyOutputPump {
    config: PtyOutputPumpConfig,
    finished: bool,
    pending: String,
    session_id: String,
    stats: PtyOutputPumpStats,
}

impl PtyOutputPump {
    pub fn new(session_id: impl Into<String>, config: PtyOutputPumpConfig) -> Self {
        Self {
            config: config.normalized(),
            finished: false,
            pending: String::new(),
            session_id: session_id.into(),
            stats: PtyOutputPumpStats::default(),
        }
    }

    pub fn push_data(&mut self, data: &str, sink: &mut impl PtyOutputSink) -> bool {
        if self.finished {
            return false;
        }
        if data.is_empty() {
            return true;
        }

        self.stats.input_chunks = self.stats.input_chunks.saturating_add(1);
        self.stats.input_bytes = self.stats.input_bytes.saturating_add(data.len() as u64);
        self.push_pending(data);
        if self.pending.len() >= self.config.flush_bytes {
            return self.flush(sink);
        }
        true
    }

    pub fn flush(&mut self, sink: &mut impl PtyOutputSink) -> bool {
        if self.finished {
            return false;
        }
        if self.pending.is_empty() {
            return true;
        }

        let data = std::mem::take(&mut self.pending);
        self.stats.data_events = self.stats.data_events.saturating_add(1);
        self.stats.output_bytes = self.stats.output_bytes.saturating_add(data.len() as u64);
        let accepted = sink.on_terminal_output(TerminalOutputEvent::data(&self.session_id, data));
        if !accepted {
            self.finished = true;
        }
        accepted
    }

    pub fn finish_closed(&mut self, sink: &mut impl PtyOutputSink) -> bool {
        if self.finished {
            return false;
        }
        if !self.flush(sink) {
            return false;
        }
        self.finished = true;
        self.stats.closed_events = self.stats.closed_events.saturating_add(1);
        sink.on_terminal_output(TerminalOutputEvent::closed(&self.session_id))
    }

    pub fn finish_error(
        &mut self,
        message: impl Into<String>,
        sink: &mut impl PtyOutputSink,
    ) -> bool {
        if self.finished {
            return false;
        }
        if !self.flush(sink) {
            return false;
        }
        self.finished = true;
        self.stats.error_events = self.stats.error_events.saturating_add(1);
        sink.on_terminal_output(TerminalOutputEvent::error(&self.session_id, message.into()))
    }

    pub fn pending_bytes(&self) -> usize {
        self.pending.len()
    }

    pub fn is_finished(&self) -> bool {
        self.finished
    }

    pub fn stats(&self) -> &PtyOutputPumpStats {
        &self.stats
    }

    fn push_pending(&mut self, data: &str) {
        if self.pending.len().saturating_add(data.len()) > self.config.max_pending_bytes {
            self.stats.overflow_count = self.stats.overflow_count.saturating_add(1);
            self.stats.dropped_bytes = self
                .stats
                .dropped_bytes
                .saturating_add(self.pending.len() as u64);
            self.pending.clear();
            self.pending.push_str(&self.config.overflow_notice);
        }

        let remaining = self
            .config
            .max_pending_bytes
            .saturating_sub(self.pending.len());
        if data.len() > remaining {
            let tail_start = tail_start_by_bytes(data, remaining);
            self.stats.dropped_bytes = self.stats.dropped_bytes.saturating_add(tail_start as u64);
            self.pending.push_str(&data[tail_start..]);
        } else {
            self.pending.push_str(data);
        }
        self.stats.max_pending_bytes = self.stats.max_pending_bytes.max(self.pending.len());
    }
}

fn tail_start_by_bytes(data: &str, max_bytes: usize) -> usize {
    if data.len() <= max_bytes {
        return 0;
    }
    let mut index = data.len() - max_bytes;
    while index < data.len() && !data.is_char_boundary(index) {
        index += 1;
    }
    index
}

//! Local shell integration launch planning.
//!
//! @author kongweiguang

use crate::models::terminal::{TerminalShellIntegrationStatus, TerminalShellIntegrationSummary};
use std::{
    collections::HashMap,
    fs, io,
    path::{Path, PathBuf},
};
use uuid::Uuid;

pub const KERMINAL_TERMINAL_ENV: &str = "KERMINAL_TERMINAL";
pub const KERMINAL_SHELL_INTEGRATION_ENV: &str = "KERMINAL_SHELL_INTEGRATION";

const SHELL_INTEGRATION_DIR: &str = "shell-integration";
const POWERSHELL_SCRIPT: &str = "kerminal-shell-integration.ps1";
const BASH_SCRIPT: &str = "kerminal-shell-integration.bash";
const ZSH_SCRIPT: &str = "kerminal-shell-integration.zsh";
const FISH_SCRIPT: &str = "kerminal-shell-integration.fish";
const ZSH_DOTDIR: &str = "zsh-dotdir";
const ZSH_RC_SCRIPT: &str = ".zshrc";

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TerminalShellLaunchPlan {
    pub shell: String,
    pub args: Vec<String>,
    pub env: HashMap<String, String>,
    pub integration: TerminalShellIntegrationSummary,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ShellIntegrationPlatform {
    Windows,
    Unix,
}

impl ShellIntegrationPlatform {
    pub fn current() -> Self {
        #[cfg(target_os = "windows")]
        {
            Self::Windows
        }

        #[cfg(not(target_os = "windows"))]
        {
            Self::Unix
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum IntegratedShellKind {
    PowerShell7,
    WindowsPowerShell,
    GitBash,
    WslBash,
    WslZsh,
    WslFish,
    Zsh,
    Bash,
    Fish,
}

impl IntegratedShellKind {
    fn id(self) -> &'static str {
        match self {
            Self::PowerShell7 => "powershell7",
            Self::WindowsPowerShell => "windowsPowerShell",
            Self::GitBash => "gitBash",
            Self::WslBash => "wslBash",
            Self::WslZsh => "wslZsh",
            Self::WslFish => "wslFish",
            Self::Zsh => "zsh",
            Self::Bash => "bash",
            Self::Fish => "fish",
        }
    }

    fn script_family(self) -> ShellScriptFamily {
        match self {
            Self::PowerShell7 | Self::WindowsPowerShell => ShellScriptFamily::PowerShell,
            Self::GitBash | Self::WslBash | Self::Bash => ShellScriptFamily::Bash,
            Self::WslZsh | Self::Zsh => ShellScriptFamily::Zsh,
            Self::WslFish | Self::Fish => ShellScriptFamily::Fish,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ShellScriptFamily {
    PowerShell,
    Bash,
    Zsh,
    Fish,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ShellIntegrationCatalog {
    platform: ShellIntegrationPlatform,
    entries: Vec<AllowedShell>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AllowedShell {
    kind: IntegratedShellKind,
    executable: PathBuf,
    canonical_executable: PathBuf,
    aliases: Vec<String>,
}

impl AllowedShell {
    pub fn new(
        kind: IntegratedShellKind,
        executable: impl Into<PathBuf>,
        aliases: impl IntoIterator<Item = impl Into<String>>,
    ) -> Self {
        let executable = executable.into();
        let canonical_executable =
            fs::canonicalize(&executable).unwrap_or_else(|_| executable.clone());
        Self {
            kind,
            canonical_executable,
            executable,
            aliases: aliases.into_iter().map(Into::into).collect(),
        }
    }
}

impl ShellIntegrationCatalog {
    pub fn detect_current() -> Self {
        Self {
            platform: ShellIntegrationPlatform::current(),
            entries: detect_allowed_shells(ShellIntegrationPlatform::current()),
        }
    }

    pub fn for_test(platform: ShellIntegrationPlatform, entries: Vec<AllowedShell>) -> Self {
        Self { platform, entries }
    }

    fn find(&self, requested_shell: &str) -> Option<&AllowedShell> {
        let requested_shell = requested_shell.trim();
        if requested_shell.is_empty() {
            return None;
        }
        let requested_lower = requested_shell.to_ascii_lowercase();
        let path_override = looks_like_path_override(requested_shell);
        let requested_canonical = if path_override {
            fs::canonicalize(requested_shell).ok()
        } else {
            None
        };

        for entry in &self.entries {
            if entry
                .aliases
                .iter()
                .any(|alias| shell_text_eq(alias, &requested_lower))
            {
                return Some(entry);
            }
            if !path_override && shell_text_eq(entry.kind.id(), &requested_lower) {
                return Some(entry);
            }
            if !path_override
                && entry
                    .executable
                    .file_name()
                    .and_then(|name| name.to_str())
                    .is_some_and(|name| shell_text_eq(name, &requested_lower))
            {
                return Some(entry);
            }
            if let Some(requested_canonical) = &requested_canonical {
                if same_path(requested_canonical, &entry.canonical_executable) {
                    return Some(entry);
                }
            }
        }

        None
    }
}

pub fn build_terminal_shell_launch(
    shell: &str,
    args: &[String],
    env: &HashMap<String, String>,
    cache_dir: &Path,
) -> TerminalShellLaunchPlan {
    build_terminal_shell_launch_with_catalog(
        shell,
        args,
        env,
        cache_dir,
        &ShellIntegrationCatalog::detect_current(),
    )
}

pub fn build_terminal_shell_launch_with_catalog(
    shell: &str,
    args: &[String],
    env: &HashMap<String, String>,
    cache_dir: &Path,
    catalog: &ShellIntegrationCatalog,
) -> TerminalShellLaunchPlan {
    if shell_integration_disabled_by_env(env) {
        return bare_launch(shell, args, env, "disabled by environment");
    }
    if !args.is_empty() {
        return bare_launch(shell, args, env, "custom shell arguments");
    }

    let Some(entry) = catalog.find(shell).cloned() else {
        return bare_launch(shell, args, env, "unsupported shell");
    };

    match ensure_shell_integration_scripts(cache_dir, catalog.platform) {
        Ok(scripts) => integrated_launch(shell, env, &entry, &scripts, catalog.platform),
        Err(error) => bare_launch(shell, args, env, &format!("script setup failed: {error}")),
    }
}

fn integrated_launch(
    requested_shell: &str,
    env: &HashMap<String, String>,
    entry: &AllowedShell,
    scripts: &ShellIntegrationScripts,
    _platform: ShellIntegrationPlatform,
) -> TerminalShellLaunchPlan {
    let mut next_env = env.clone();
    next_env.insert(KERMINAL_TERMINAL_ENV.to_owned(), "1".to_owned());
    next_env.insert(KERMINAL_SHELL_INTEGRATION_ENV.to_owned(), "1".to_owned());
    if next_env
        .get("TERM")
        .map(|value| value.trim().is_empty() || value == "dumb")
        .unwrap_or(true)
    {
        next_env.insert("TERM".to_owned(), "xterm-256color".to_owned());
    }
    next_env
        .entry("COLORTERM".to_owned())
        .or_insert_with(|| "truecolor".to_owned());
    if entry.kind == IntegratedShellKind::Zsh {
        next_env.insert(
            "ZDOTDIR".to_owned(),
            scripts.zsh_dotdir.to_string_lossy().into_owned(),
        );
    }

    let script_path = scripts.script_path_for(entry.kind);
    let args = integration_args(entry.kind, script_path, scripts);
    TerminalShellLaunchPlan {
        shell: entry.executable.to_string_lossy().into_owned(),
        args,
        env: next_env,
        integration: TerminalShellIntegrationSummary {
            status: TerminalShellIntegrationStatus::Enabled,
            shell: Some(entry.kind.id().to_owned()),
            script_path: Some(script_path.to_string_lossy().into_owned()),
            reason: None,
        },
    }
    .with_requested_shell_fallback(requested_shell)
}

trait RequestedShellFallback {
    fn with_requested_shell_fallback(self, requested_shell: &str) -> Self;
}

impl RequestedShellFallback for TerminalShellLaunchPlan {
    fn with_requested_shell_fallback(mut self, requested_shell: &str) -> Self {
        if self.shell.trim().is_empty() {
            self.shell = requested_shell.to_owned();
        }
        self
    }
}

fn bare_launch(
    shell: &str,
    args: &[String],
    env: &HashMap<String, String>,
    reason: &str,
) -> TerminalShellLaunchPlan {
    TerminalShellLaunchPlan {
        shell: shell.to_owned(),
        args: args.to_vec(),
        env: env.clone(),
        integration: TerminalShellIntegrationSummary {
            status: TerminalShellIntegrationStatus::Disabled,
            shell: None,
            script_path: None,
            reason: Some(reason.to_owned()),
        },
    }
}

fn integration_args(
    kind: IntegratedShellKind,
    script_path: &Path,
    scripts: &ShellIntegrationScripts,
) -> Vec<String> {
    match kind {
        IntegratedShellKind::PowerShell7 | IntegratedShellKind::WindowsPowerShell => vec![
            "-NoLogo".to_owned(),
            "-NoExit".to_owned(),
            "-ExecutionPolicy".to_owned(),
            "Bypass".to_owned(),
            "-File".to_owned(),
            script_path.to_string_lossy().into_owned(),
        ],
        IntegratedShellKind::GitBash => vec![
            "--init-file".to_owned(),
            path_to_msys(script_path).unwrap_or_else(|| script_path.to_string_lossy().into_owned()),
            "-i".to_owned(),
        ],
        IntegratedShellKind::Bash => vec![
            "--init-file".to_owned(),
            script_path.to_string_lossy().into_owned(),
            "-i".to_owned(),
        ],
        IntegratedShellKind::Zsh => vec!["-i".to_owned()],
        IntegratedShellKind::Fish => vec![
            "--interactive".to_owned(),
            "--init-command".to_owned(),
            format!("source {}", fish_quote(&script_path.to_string_lossy())),
        ],
        IntegratedShellKind::WslBash => vec![
            "--exec".to_owned(),
            "bash".to_owned(),
            "--init-file".to_owned(),
            path_to_wsl(script_path).unwrap_or_else(|| script_path.to_string_lossy().into_owned()),
            "-i".to_owned(),
        ],
        IntegratedShellKind::WslZsh => vec![
            "--exec".to_owned(),
            "env".to_owned(),
            format!(
                "ZDOTDIR={}",
                path_to_wsl(&scripts.zsh_dotdir)
                    .unwrap_or_else(|| scripts.zsh_dotdir.to_string_lossy().into_owned())
            ),
            "zsh".to_owned(),
            "-i".to_owned(),
        ],
        IntegratedShellKind::WslFish => vec![
            "--exec".to_owned(),
            "fish".to_owned(),
            "--interactive".to_owned(),
            "--init-command".to_owned(),
            format!(
                "source {}",
                fish_quote(
                    &path_to_wsl(script_path)
                        .unwrap_or_else(|| script_path.to_string_lossy().into_owned())
                )
            ),
        ],
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ShellIntegrationScripts {
    powershell: PathBuf,
    bash: PathBuf,
    zsh: PathBuf,
    fish: PathBuf,
    zsh_dotdir: PathBuf,
}

impl ShellIntegrationScripts {
    fn script_path_for(&self, kind: IntegratedShellKind) -> &Path {
        match kind.script_family() {
            ShellScriptFamily::PowerShell => &self.powershell,
            ShellScriptFamily::Bash => &self.bash,
            ShellScriptFamily::Zsh => &self.zsh,
            ShellScriptFamily::Fish => &self.fish,
        }
    }
}

fn ensure_shell_integration_scripts(
    cache_dir: &Path,
    platform: ShellIntegrationPlatform,
) -> io::Result<ShellIntegrationScripts> {
    let root = cache_dir.join(SHELL_INTEGRATION_DIR);
    fs::create_dir_all(&root)?;
    let scripts = ShellIntegrationScripts {
        powershell: root.join(POWERSHELL_SCRIPT),
        bash: root.join(BASH_SCRIPT),
        zsh: root.join(ZSH_SCRIPT),
        fish: root.join(FISH_SCRIPT),
        zsh_dotdir: root.join(ZSH_DOTDIR),
    };

    write_script_atomic(&scripts.powershell, powershell_script())?;
    write_script_atomic(&scripts.bash, bash_script())?;
    write_script_atomic(&scripts.zsh, zsh_script())?;
    write_script_atomic(&scripts.fish, fish_script())?;

    fs::create_dir_all(&scripts.zsh_dotdir)?;
    write_script_atomic(
        &scripts.zsh_dotdir.join(ZSH_RC_SCRIPT),
        &zsh_dotdir_script(&scripts.zsh, platform),
    )?;

    Ok(scripts)
}

fn write_script_atomic(path: &Path, content: &str) -> io::Result<()> {
    if fs::read_to_string(path).is_ok_and(|current| current == content) {
        return Ok(());
    }
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    let tmp_path = path.with_extension(format!("tmp-{}", Uuid::new_v4()));
    fs::write(&tmp_path, content)?;
    replace_file_atomic(&tmp_path, path)?;
    Ok(())
}

#[cfg(not(target_os = "windows"))]
fn replace_file_atomic(tmp_path: &Path, path: &Path) -> io::Result<()> {
    fs::rename(tmp_path, path)
}

#[cfg(target_os = "windows")]
fn replace_file_atomic(tmp_path: &Path, path: &Path) -> io::Result<()> {
    use windows_sys::Win32::Storage::FileSystem::{
        MoveFileExW, MOVEFILE_REPLACE_EXISTING, MOVEFILE_WRITE_THROUGH,
    };

    let tmp_wide = wide_null(tmp_path.as_os_str());
    let path_wide = wide_null(path.as_os_str());
    let ok = unsafe {
        MoveFileExW(
            tmp_wide.as_ptr(),
            path_wide.as_ptr(),
            MOVEFILE_REPLACE_EXISTING | MOVEFILE_WRITE_THROUGH,
        )
    };
    if ok == 0 {
        let error = io::Error::last_os_error();
        let _ = fs::remove_file(tmp_path);
        return Err(error);
    }
    Ok(())
}

#[cfg(target_os = "windows")]
fn wide_null(value: &std::ffi::OsStr) -> Vec<u16> {
    use std::os::windows::ffi::OsStrExt;

    value.encode_wide().chain(std::iter::once(0)).collect()
}

fn detect_allowed_shells(platform: ShellIntegrationPlatform) -> Vec<AllowedShell> {
    match platform {
        ShellIntegrationPlatform::Windows => detect_windows_shells(),
        ShellIntegrationPlatform::Unix => detect_unix_shells(),
    }
}

fn detect_windows_shells() -> Vec<AllowedShell> {
    let mut entries = Vec::new();
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::PowerShell7,
        "pwsh.exe",
        &[
            r"C:\Program Files\PowerShell\7\pwsh.exe",
            r"C:\Program Files (x86)\PowerShell\7\pwsh.exe",
        ],
        ["pwsh", "pwsh.exe", "powershell7", "powershell-core"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::WindowsPowerShell,
        "powershell.exe",
        &[r"C:\Windows\System32\WindowsPowerShell\v1.0\powershell.exe"],
        ["powershell", "powershell.exe", "windows-powershell"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::GitBash,
        "bash.exe",
        &[
            r"C:\Program Files\Git\bin\bash.exe",
            r"C:\Program Files\Git\usr\bin\bash.exe",
        ],
        ["git-bash", "gitBash", "bash.exe"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::WslBash,
        "wsl.exe",
        &[r"C:\Windows\System32\wsl.exe"],
        ["wsl", "wsl.exe", "wsl:bash", "wslBash"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::WslZsh,
        "wsl.exe",
        &[r"C:\Windows\System32\wsl.exe"],
        ["wsl:zsh", "wslZsh"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::WslFish,
        "wsl.exe",
        &[r"C:\Windows\System32\wsl.exe"],
        ["wsl:fish", "wslFish"],
    );
    entries
}

fn detect_unix_shells() -> Vec<AllowedShell> {
    let mut entries = Vec::new();
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::Zsh,
        "zsh",
        &["/bin/zsh", "/usr/bin/zsh"],
        ["zsh"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::Bash,
        "bash",
        &["/bin/bash", "/usr/bin/bash"],
        ["bash"],
    );
    push_detected_shell(
        &mut entries,
        IntegratedShellKind::Fish,
        "fish",
        &["/bin/fish", "/usr/bin/fish"],
        ["fish"],
    );
    entries
}

fn push_detected_shell<const N: usize>(
    entries: &mut Vec<AllowedShell>,
    kind: IntegratedShellKind,
    command: &str,
    common_paths: &[&str],
    aliases: [&str; N],
) {
    if entries.iter().any(|entry| entry.kind == kind) {
        return;
    }
    if let Ok(path) = which::which(command) {
        entries.push(AllowedShell::new(kind, path, aliases));
        return;
    }
    for path in common_paths {
        let path = PathBuf::from(path);
        if path.exists() {
            entries.push(AllowedShell::new(kind, path, aliases));
            return;
        }
    }
}

fn shell_integration_disabled_by_env(env: &HashMap<String, String>) -> bool {
    env.get(KERMINAL_SHELL_INTEGRATION_ENV)
        .map(|value| {
            let value = value.trim().to_ascii_lowercase();
            value == "0" || value == "false" || value == "off" || value == "disabled"
        })
        .unwrap_or(false)
}

fn looks_like_path_override(value: &str) -> bool {
    value.contains('/') || value.contains('\\') || value.contains(':')
}

fn shell_text_eq(left: &str, right_lower: &str) -> bool {
    left.eq_ignore_ascii_case(right_lower)
}

fn same_path(left: &Path, right: &Path) -> bool {
    let left = left.to_string_lossy();
    let right = right.to_string_lossy();
    if cfg!(target_os = "windows") {
        left.eq_ignore_ascii_case(&right)
    } else {
        left == right
    }
}

fn path_to_msys(path: &Path) -> Option<String> {
    windows_drive_path(path).map(|(drive, tail)| format!("/{drive}/{tail}"))
}

fn path_to_wsl(path: &Path) -> Option<String> {
    windows_drive_path(path).map(|(drive, tail)| format!("/mnt/{drive}/{tail}"))
}

fn windows_drive_path(path: &Path) -> Option<(char, String)> {
    let raw = path.to_string_lossy().replace('\\', "/");
    let mut chars = raw.chars();
    let drive = chars.next()?.to_ascii_lowercase();
    if !drive.is_ascii_alphabetic() || chars.next()? != ':' {
        return None;
    }
    let tail = chars.as_str().trim_start_matches('/').to_owned();
    Some((drive, tail))
}

fn fish_quote(value: &str) -> String {
    format!("'{}'", value.replace('\'', "\\'"))
}

