            "Bypass".to_owned(),
            "-Command".to_owned(),
            format!(
                "& {} {}",
                powershell_quote(&node),
                powershell_quote(node_script)
            ),
        ],
    };
    ShellMatrixCase::runnable(name, terminal_request(shell, args))
}

#[cfg(target_os = "windows")]
fn discover_git_bash_case(node_script: &Path) -> ShellMatrixCase {
